import{c as e,Q as a,j as o,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Don't Break the Cache: Efficient Prompt Caching for Agentic AI","description":"","frontmatter":{"title":"Don't Break the Cache: Efficient Prompt Caching for Agentic AI","authors":"Benedikt Kolbe, Rania Mokhtar, David Müller, Barna Szabó","published":"2026-01-31T00:00:00.000Z","source":"https://arxiv.org/abs/2601.06007"},"headers":[],"relativePath":"research/papers/2026-01-31-dont-break-cache-prompt-caching-2601-06007.md","filePath":"research/papers/2026-01-31-dont-break-cache-prompt-caching-2601-06007.md","lastUpdated":1779901665000}`),s={name:"research/papers/2026-01-31-dont-break-cache-prompt-caching-2601-06007.md"};function r(i,t,c,l,d,h){return a(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="don-t-break-the-cache-efficient-prompt-caching-for-agentic-ai" tabindex="-1">Don&#39;t Break the Cache: Efficient Prompt Caching for Agentic AI <a class="header-anchor" href="#don-t-break-the-cache-efficient-prompt-caching-for-agentic-ai" aria-label="Permalink to &quot;Don&#39;t Break the Cache: Efficient Prompt Caching for Agentic AI&quot;">​</a></h1><p><strong>Authors</strong>: Benedikt Kolbe, Rania Mokhtar, David Müller, Barna Szabó <strong>Published</strong>: January 31, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2601.06007" target="_blank" rel="noreferrer">https://arxiv.org/abs/2601.06007</a><strong>arXiv ID</strong>: 2601.06007 <strong>Categories</strong>: cs.AI, cs.LG</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Prompt caching can reduce LLM API costs by 41–80% in agentic workflows, but cache invalidation from dynamic content is a critical, underexplored risk. This paper systematically evaluates three caching strategies for agentic AI coding tools, identifies the most common cache-breaking patterns, and recommends system-prompt-only caching as the optimal default strategy (78.5% cost reduction, 22.9% TTFT improvement with Claude Sonnet 4.5).</p><hr><h2 id="background-how-prompt-caching-works" tabindex="-1">Background: How Prompt Caching Works <a class="header-anchor" href="#background-how-prompt-caching-works" aria-label="Permalink to &quot;Background: How Prompt Caching Works&quot;">​</a></h2><h3 id="provider-implementations" tabindex="-1">Provider Implementations <a class="header-anchor" href="#provider-implementations" aria-label="Permalink to &quot;Provider Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Provider</th><th>Activation</th><th>Min Token Threshold</th><th>Cache TTL</th></tr></thead><tbody><tr><td>Anthropic</td><td>Explicit <code>cache_control</code> parameter</td><td>1,024 tokens</td><td>5 min (extendable to 1 hr)</td></tr><tr><td>OpenAI</td><td>Automatic (no API change needed)</td><td>1,024 tokens</td><td>~5–10 min</td></tr><tr><td>Google Gemini</td><td>Automatic</td><td>4,096 tokens</td><td>1 min–1 day</td></tr></tbody></table><p><strong>Mechanism</strong>: Caching reuses precomputed KV (Key-Value) states from the transformer&#39;s attention layers. When the prefix of a prompt matches a cached entry, computation for that prefix is skipped.</p><h3 id="cost-reduction-mechanics" tabindex="-1">Cost Reduction Mechanics <a class="header-anchor" href="#cost-reduction-mechanics" aria-label="Permalink to &quot;Cost Reduction Mechanics&quot;">​</a></h3><p>Cache hits are billed at a lower rate:</p><ul><li>Anthropic: ~90% discount on cached tokens</li><li>OpenAI: 50% discount on cached input tokens</li><li>Google: 75–85% discount</li></ul><hr><h2 id="three-caching-strategies-evaluated" tabindex="-1">Three Caching Strategies Evaluated <a class="header-anchor" href="#three-caching-strategies-evaluated" aria-label="Permalink to &quot;Three Caching Strategies Evaluated&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Description</th><th>Scope</th></tr></thead><tbody><tr><td><strong>System-Prompt-Only</strong></td><td>Cache only the static system prompt</td><td>Fixed portion of context</td></tr><tr><td><strong>Full-Context</strong></td><td>Cache entire conversation history including tool results</td><td>All turns</td></tr><tr><td><strong>Exclude-Tool-Results</strong></td><td>Cache everything except dynamic tool outputs</td><td>History minus tool responses</td></tr></tbody></table><hr><h2 id="results-strategy-comparison-claude-sonnet-4-5" tabindex="-1">Results: Strategy Comparison (Claude Sonnet 4.5) <a class="header-anchor" href="#results-strategy-comparison-claude-sonnet-4-5" aria-label="Permalink to &quot;Results: Strategy Comparison (Claude Sonnet 4.5)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Strategy</th><th>Cost Reduction</th><th>TTFT Improvement</th><th>Cache Hit Rate</th></tr></thead><tbody><tr><td><strong>System-Prompt-Only</strong></td><td><strong>78.5%</strong></td><td><strong>22.9%</strong></td><td>Highest</td></tr><tr><td>Full-Context</td><td>41–60%</td><td>Variable</td><td>Moderate</td></tr><tr><td>Exclude-Tool-Results</td><td>55–70%</td><td>Moderate</td><td>Moderate</td></tr></tbody></table><p><strong>Key finding</strong>: System-prompt-only caching is the most consistent strategy. Full-context caching can achieve higher absolute savings but is vulnerable to cache invalidation from dynamic content.</p><hr><h2 id="cache-breaking-patterns" tabindex="-1">Cache-Breaking Patterns <a class="header-anchor" href="#cache-breaking-patterns" aria-label="Permalink to &quot;Cache-Breaking Patterns&quot;">​</a></h2><p>The paper identifies the most common sources of cache invalidation in agentic workflows:</p><h3 id="_1-dynamic-tool-results" tabindex="-1">1. Dynamic Tool Results <a class="header-anchor" href="#_1-dynamic-tool-results" aria-label="Permalink to &quot;1. Dynamic Tool Results&quot;">​</a></h3><p>Tool outputs (file reads, web fetches, shell commands) vary between calls → any token in the cached prefix after a tool result is invalidated.</p><h3 id="_2-timestamps-and-uuids" tabindex="-1">2. Timestamps and UUIDs <a class="header-anchor" href="#_2-timestamps-and-uuids" aria-label="Permalink to &quot;2. Timestamps and UUIDs&quot;">​</a></h3><p>System prompts or messages containing <code>datetime.now()</code>, request IDs, or session UUIDs break the cache prefix on every call.</p><h3 id="_3-mcp-model-context-protocol-servers" tabindex="-1">3. MCP (Model Context Protocol) Servers <a class="header-anchor" href="#_3-mcp-model-context-protocol-servers" aria-label="Permalink to &quot;3. MCP (Model Context Protocol) Servers&quot;">​</a></h3><p>MCP tool definitions are injected dynamically at runtime. If MCP tool lists change between calls (e.g., server restarts, capability negotiation), the tool block in the system prompt changes → <strong>MCP breaks cache boundaries</strong>.</p><h3 id="_4-conversation-turn-insertion" tabindex="-1">4. Conversation Turn Insertion <a class="header-anchor" href="#_4-conversation-turn-insertion" aria-label="Permalink to &quot;4. Conversation Turn Insertion&quot;">​</a></h3><p>Inserting a new user/assistant turn in the middle of a cached conversation invalidates everything after the insertion point.</p><hr><h2 id="provider-specific-findings" tabindex="-1">Provider-Specific Findings <a class="header-anchor" href="#provider-specific-findings" aria-label="Permalink to &quot;Provider-Specific Findings&quot;">​</a></h2><h3 id="anthropic" tabindex="-1">Anthropic <a class="header-anchor" href="#anthropic" aria-label="Permalink to &quot;Anthropic&quot;">​</a></h3><ul><li>Requires explicit <code>cache_control: {&quot;type&quot;: &quot;ephemeral&quot;}</code> on the content block to cache</li><li>Cache TTL defaults to 5 minutes; can request extended TTL up to 1 hour</li><li>Tool definitions count toward the cacheable prefix if placed before the <code>cache_control</code> marker</li></ul><h3 id="openai" tabindex="-1">OpenAI <a class="header-anchor" href="#openai" aria-label="Permalink to &quot;OpenAI&quot;">​</a></h3><ul><li>Automatic prefix caching (no API change) at 1,024-token minimum</li><li>Cache granularity: 128-token chunks</li><li>Does not expose cache hit/miss in standard response (only via usage metadata)</li></ul><h3 id="google-gemini" tabindex="-1">Google Gemini <a class="header-anchor" href="#google-gemini" aria-label="Permalink to &quot;Google Gemini&quot;">​</a></h3><ul><li>Explicit <code>cachedContent</code> API for system instruction caching</li><li>4,096-token minimum is higher barrier for short system prompts</li><li>TTL configurable from 1 minute to 1 day — useful for batch processing</li></ul><hr><h2 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h2><h3 id="for-agentic-ai-coding-tools" tabindex="-1">For Agentic AI Coding Tools <a class="header-anchor" href="#for-agentic-ai-coding-tools" aria-label="Permalink to &quot;For Agentic AI Coding Tools&quot;">​</a></h3><ol><li><strong>Cache only the static system prompt</strong> (system-prompt-only strategy) — highest consistency</li><li><strong>Keep tool definitions static</strong>: avoid adding/removing MCP tools mid-session</li><li><strong>Remove dynamic content from system prompt</strong>: no timestamps, session IDs, or per-request state</li><li><strong>Place dynamic content last</strong>: structure prompts as <code>[static system prompt][static tool defs][dynamic history]</code></li></ol><h3 id="anti-patterns-to-avoid" tabindex="-1">Anti-Patterns to Avoid <a class="header-anchor" href="#anti-patterns-to-avoid" aria-label="Permalink to &quot;Anti-Patterns to Avoid&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ System prompt with datetime.now()  →  breaks cache every second</span></span>
<span class="line"><span>❌ Tool results placed before cache_control marker  →  invalidates on every tool call</span></span>
<span class="line"><span>❌ MCP server restart between calls  →  tool list changes, cache miss</span></span>
<span class="line"><span>❌ UUID in system prompt header  →  unique per session, zero cache hits</span></span></code></pre></div><h3 id="recommended-prompt-structure" tabindex="-1">Recommended Prompt Structure <a class="header-anchor" href="#recommended-prompt-structure" aria-label="Permalink to &quot;Recommended Prompt Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[CACHED]</span></span>
<span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>  Static instructions (no dynamic content)</span></span>
<span class="line"><span>  Static tool definitions</span></span>
<span class="line"><span>  Static context documents</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span>[cache_control marker here]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[DYNAMIC — NOT CACHED]</span></span>
<span class="line"><span>&lt;tool_result&gt;...&lt;/tool_result&gt;</span></span>
<span class="line"><span>&lt;human&gt;...&lt;/human&gt;</span></span>
<span class="line"><span>&lt;assistant&gt;...&lt;/assistant&gt;</span></span></code></pre></div><hr><h2 id="economic-impact-at-scale" tabindex="-1">Economic Impact at Scale <a class="header-anchor" href="#economic-impact-at-scale" aria-label="Permalink to &quot;Economic Impact at Scale&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scale</th><th>Annual API Spend</th><th>Savings (System-Prompt-Only at 78.5%)</th></tr></thead><tbody><tr><td>Startup (100K calls/day)</td><td>~$36,500</td><td>~$28,600</td></tr><tr><td>Mid-size (1M calls/day)</td><td>~$365,000</td><td>~$286,600</td></tr><tr><td>Enterprise (10M calls/day)</td><td>~$3,650,000</td><td>~$2,866,000</td></tr></tbody></table><p>TTFT (time-to-first-token) improvement of 22.9% is independently valuable for interactive tools where latency matters.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Directly actionable for workspace prompt caching configuration:</p><ol><li><strong>78.5% cost reduction with system-prompt-only</strong>: The workspace CLAUDE.md / AGENTS.md system prompt is static — this is exactly the target for caching. Apply <code>cache_control</code> to the static system prompt block.</li><li><strong>MCP breaks cache boundaries</strong>: Any MCP server restart or tool-list change during a session invalidates the cache. Keep MCP tool lists stable within a session — don&#39;t add/remove MCP servers mid-task.</li><li><strong>No timestamps in CLAUDE.md</strong>: Avoid including <code>currentDate</code> or session IDs in the auto-loaded system prompt (<code>@core.md</code>, <code>@output-discipline.md</code>) — these break caching.</li><li><strong>Dynamic tool results must come AFTER the cache marker</strong>: In multi-tool agentic loops (<code>autoresearch</code>, <code>harness-meta</code>), place tool results in the dynamic (uncached) portion of context.</li><li><strong>22.9% TTFT improvement</strong>: Prompt caching also reduces latency — relevant for interactive <code>sonnet-pilot</code> sessions where response time affects usability.</li></ol>`,55)])])}const u=e(s,[["render",r]]);export{m as __pageData,u as default};
